// src/enrollment/application/EnrollStudent.ts
import { CourseRepository } from '../domain/CourseRepository';
import { StudentRepository } from '../domain/StudentRepository';

export class EnrollStudent {
  constructor(
    private courseRepo: CourseRepository,
    private studentRepo: StudentRepository
  ) {}

  async execute(courseId: string, studentId: string): Promise<void> {
    const course = await this.courseRepo.search(courseId);
    if (!course) {
      throw new Error('Course not found');
    }
    const student = await this.studentRepo.search(studentId);
    if (!student) {
      throw new Error('Student not found');
    }
    if (course.students.length >= course.maxCapacity) {
      throw new Error('Course is full');
    }
    course.students.push(student);
    await this.courseRepo.save(course);
  }
}
