// src/features/product/page.tsx
'use client';

import { useState, useEffect } from 'react';

export default function ProductPage({ params }: { params: { id: string } }) {
  const [product, setProduct] = useState(null);
  const [reviews, setReviews] = useState([]);
  const [relatedProducts, setRelatedProducts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      const productRes = await fetch(`/api/products/${params.id}`);
      const productData = await productRes.json();
      setProduct(productData);

      const reviewsRes = await fetch(`/api/products/${params.id}/reviews`);
      const reviewsData = await reviewsRes.json();
      setReviews(reviewsData);

      const relatedRes = await fetch(`/api/products/${params.id}/related`);
      const relatedData = await relatedRes.json();
      setRelatedProducts(relatedData);

      setIsLoading(false);
    }
    fetchData();
  }, [params.id]);

  const [isOnSale, setIsOnSale] = useState(false);
  useEffect(() => {
    if (product) {
      setIsOnSale(product.originalPrice > product.price);
    }
  }, [product]);

  if (isLoading) return <div>Loading...</div>;

  return (
    <div>
      <h1>{product.name}</h1>
      <p>${product.price}</p>
      {isOnSale && <span>On Sale!</span>}
      <div>
        <h2>Reviews</h2>
        {reviews.map(r => <div key={r.id}>{r.text}</div>)}
      </div>
      <div>
        <h2>Related</h2>
        {relatedProducts.map(p => <div key={p.id}>{p.name}</div>)}
      </div>
    </div>
  );
}
