Review the following payment processing module for OOP design quality.

```typescript
// src/payments/application/PaymentProcessor.ts
import { StripeClient } from '../infrastructure/StripeClient';
import { PaymentRepository } from '../domain/PaymentRepository';

export class PaymentProcessor {
  constructor(
    private stripeClient: StripeClient,
    private repo: PaymentRepository
  ) {}

  async process(orderId: string, amount: number, currency: string, cardToken: string): Promise<void> {
    const charge = await this.stripeClient.createCharge({
      amount: amount * 100,
      currency,
      source: cardToken,
    });

    if (charge.status === 'succeeded') {
      const payment = {
        id: charge.id,
        orderId,
        amount,
        currency,
        status: 'completed',
        processedAt: new Date(),
      };
      await this.repo.save(payment);
    } else if (charge.status === 'failed') {
      const payment = {
        id: charge.id,
        orderId,
        amount,
        currency,
        status: 'failed',
        processedAt: new Date(),
      };
      await this.repo.save(payment);
    }
  }

  async getPaymentDetails(paymentId: string) {
    const payment = await this.repo.find(paymentId);
    return {
      id: payment.id,
      amount: payment.amount / 100,
      displayAmount: `$${(payment.amount / 100).toFixed(2)}`,
      status: payment.status,
      date: payment.processedAt.toISOString(),
    };
  }
}
