```tsx
// src/features/checkout/components/CheckoutForm.tsx
'use client';

import { useState } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';

const checkoutSchema = z.object({
  name: z.string().min(1, 'Name is required'),
  email: z.string().email('Invalid email'),
  cardNumber: z.string().min(16, 'Card number must be 16 digits'),
});

type CheckoutData = z.infer<typeof checkoutSchema>;

export function CheckoutForm() {
  const [serverError, setServerError] = useState<string | null>(null);
  const { register, handleSubmit, formState: { errors, isSubmitting } } = useForm<CheckoutData>({
    resolver: zodResolver(checkoutSchema),
  });

  const onSubmit = async (data: CheckoutData) => {
    try {
      const res = await fetch('/api/checkout', { method: 'POST', body: JSON.stringify(data) });
      if (res.status === 400) {
        const body = await res.json();
        setServerError(body.message);
      }
    } catch (e) {
      setServerError('Network error');
    }
  };

  return (
    <form onSubmit={handleSubmit(onSubmit)}>
      <input {...register('name')} placeholder="Name" />
      {errors.name && <span>{errors.name.message}</span>}
      <input {...register('email')} placeholder="Email" />
      {errors.email && <span>{errors.email.message}</span>}
      <input {...register('cardNumber')} placeholder="Card Number" />
      {errors.cardNumber && <span>{errors.cardNumber.message}</span>}
      {serverError && <div role="alert">{serverError}</div>}
      <button type="submit" disabled={isSubmitting}>Place Order</button>
    </form>
  );
}
