// src/notifications/application/NotificationService.ts
import { SendGridClient } from '../infrastructure/SendGridClient';
import { TwilioClient } from '../infrastructure/TwilioClient';
import { SlackWebhook } from '../infrastructure/SlackWebhook';
import { UserRepository } from '../domain/UserRepository';

export class NotificationService {
  private emailClient: SendGridClient;
  private smsClient: TwilioClient;
  private slackClient: SlackWebhook;

  constructor(private readonly userRepo: UserRepository) {
    this.emailClient = new SendGridClient(process.env.SENDGRID_API_KEY!);
    this.smsClient = new TwilioClient(process.env.TWILIO_SID!, process.env.TWILIO_TOKEN!);
    this.slackClient = new SlackWebhook(process.env.SLACK_WEBHOOK_URL!);
  }

  async notifyUser(userId: string, message: string, channel: 'email' | 'sms' | 'slack'): Promise<void> {
    const user = await this.userRepo.findById(userId);
    if (!user) throw new Error('User not found');

    switch (channel) {
      case 'email':
        await this.emailClient.send(user.email, 'Notification', message);
        break;
      case 'sms':
        await this.smsClient.sendSms(user.phone, message);
        break;
      case 'slack':
        await this.slackClient.post(user.slackId, message);
        break;
      default:
        throw new Error(`Unknown channel: ${channel}`);
    }
  }

  async notifyAll(userIds: string[], message: string, channel: 'email' | 'sms' | 'slack'): Promise<void> {
    for (const id of userIds) {
      await this.notifyUser(id, message, channel);
    }
  }
}
